/*
  # Seed Services page blocks — Tigwire Services

  Ports the business plan's full 11-item "Services Offered" list into
  page_blocks, reusing the header/service_grid/pricing_notes block types.

  Pricing note: the source document (Executive_Summary.docx) describes a
  pricing *basis* (premises size, cleaning type, frequency, labor,
  equipment, materials) and contract *types* (daily/weekly/monthly/annual),
  but gives no actual dollar or MWK figures for any individual service —
  unlike the original Austin Phiri Advisory migration this replaces, which
  had real fixed price ranges to draw from. Every service below is
  therefore seeded with cta_type "custom" and a price field that describes
  how pricing is determined rather than inventing a number. Update these
  once real rate cards exist.

  ServiceGridBlock.tsx's icon lookup was extended for this migration (see
  that file) to include cleaning-relevant icons, replacing the governance-
  specific set (Shield, Search, GraduationCap, etc.) it previously offered.
*/

INSERT INTO page_blocks (page, type, position, content)
VALUES ('services', 'header', 0, '{"title":"Services & Pricing","intro":"Professional cleaning and facility services for homes, offices, schools, hotels, and banks — priced fairly around your space and your needs."}'::jsonb);

INSERT INTO page_blocks (page, type, position, content)
VALUES ('services', 'service_grid', 1, '{"services":[{"icon":"Home","title":"Residential Standard Cleaning","description":"Regular cleaning for homes — living areas, bedrooms, kitchens, and bathrooms — on a schedule that suits your household.","outcome":"A consistently clean home without lifting a finger.","price":"Priced by assessment","price_note":"Based on home size and visit frequency","cta_type":"custom"},{"icon":"Sparkles","title":"Deep Cleaning","description":"A thorough, top-to-bottom clean covering areas a standard visit does not reach — ideal for a seasonal reset or before a special occasion.","outcome":"Every corner addressed, not just the surface.","price":"Priced by assessment","price_note":"Based on space size and condition","cta_type":"custom"},{"icon":"Truck","title":"Move-In & Move-Out Cleaning","description":"A full clean of an empty property before you move in or hand over the keys, so the space is ready either way.","outcome":"A move-in ready home, or a deposit-ready handover.","price":"Priced by assessment","price_note":"Based on property size","cta_type":"custom"},{"icon":"Building2","title":"Office Cleaning","description":"Scheduled cleaning for offices and commercial spaces — desks, common areas, kitchens, and washrooms — on a daily, weekly, or monthly contract.","outcome":"A consistently presentable workplace for your staff and clients.","price":"Priced by assessment","price_note":"Based on premises size and contract frequency","cta_type":"custom"},{"icon":"Layers","title":"Carpet Cleaning","description":"Deep carpet and rug cleaning to lift embedded dirt and refresh flooring in homes, offices, and commercial premises.","outcome":"Carpets that look and feel genuinely refreshed.","price":"Priced by assessment","price_note":"Based on area and carpet condition","cta_type":"custom"},{"icon":"AppWindow","title":"Window Cleaning","description":"Interior and exterior window cleaning for homes, offices, and larger commercial buildings.","outcome":"Streak-free, clear windows inside and out.","price":"Priced by assessment","price_note":"Based on number and accessibility of windows","cta_type":"custom"},{"icon":"ArrowUpFromDot","title":"Ceiling Cleaning","description":"Cleaning of ceilings and high surfaces that routine cleaning does not reach, removing dust, cobwebs, and buildup.","outcome":"A genuinely complete clean, top to bottom.","price":"Priced by assessment","price_note":"Based on ceiling height and area","cta_type":"custom"},{"icon":"Droplets","title":"Disinfection Service","description":"Targeted disinfection for homes, offices, schools, hotels, and banks, using products chosen to be effective and safe for occupants.","outcome":"A genuinely sanitised space, not just a visibly clean one.","price":"Priced by assessment","price_note":"Based on area and disinfection scope","cta_type":"custom"},{"icon":"Trees","title":"Landscaping","description":"Grounds and outdoor space maintenance to keep the exterior of your property as well-kept as the interior.","outcome":"Grounds that match the standard of the building.","price":"Priced by assessment","price_note":"Based on outdoor area and scope","cta_type":"custom"},{"icon":"Trash2","title":"Waste Collection Support","description":"Support with routine waste collection and disposal as part of an ongoing cleaning contract.","outcome":"One less logistical concern for your facility.","price":"Priced by assessment","price_note":"Based on volume and collection frequency","cta_type":"custom"},{"icon":"HardHat","title":"Post-Construction Cleaning","description":"Thorough cleanup of dust, debris, and residue after building or renovation work, so the space is ready for use.","outcome":"A genuinely move-in-ready space after the builders leave.","price":"Priced by assessment","price_note":"Based on site size and post-construction condition","cta_type":"custom"}]}'::jsonb);

INSERT INTO page_blocks (page, type, position, content)
VALUES ('services', 'pricing_notes', 2, '{"heading":"📌 Pricing Notes","items":["<strong>Every quote is based on your specific space</strong> — pricing depends on the size of the premises, type of cleaning required, frequency of service, labour and equipment needed, and cleaning materials used.","<strong>Free site inspections</strong> are available so we can assess your space accurately before agreeing a price — no guesswork, no surprises.","We offer <strong>daily, weekly, monthly, and annual</strong> contracts, so pricing can reflect a one-time job or a long-term arrangement.","Prices are quoted in <strong>Malawi Kwacha (MWK)</strong> unless otherwise agreed.","All ongoing contracts are covered by a clear service agreement setting out scope, schedule, and price."],"framework_note":"Get in touch for a <strong>free, no-obligation quote</strong> tailored to your space and schedule."}'::jsonb);